    ```javascript
    module.exports = {
      async headers() {
        return [
          {
            source: '/(.*)',
            headers: [
              { key: 'Content-Security-Policy', value: "default-src 'self'" },
              { key: 'X-Frame-Options', value: 'SAMEORIGIN' },
              // Add other security headers as needed
            ],
          },
        ];
      },
    };
    ```
